mapper.select:
select spi.id as rowId ,spi.data_status as dataStatus, spi.patent_no as patentNo ,spi.ann_no as annNo,spi.ann_date as annDate, spi.name as name ,spi.apply_date as applyDate,spi.apply_no as applyNo, spi.is_pct as isPct ,spi.cooperation_type as cooperationType, spi.pct_code as pctCode ,spi.pct_name as pctName, spi.pct_date as pctDate ,spi.pct_priority_date as pctPriorityDate, spi.certificate_no as certificateNo ,spapply.name as applyPatentName, csy.name as yearName, sps.name as stateName, fdept.name as deptName, fuser.name as subUserName, csuo.name as ourUnitRankingName, spt.name as patentTypeName from srm_patent_info spi left join ct_srm_year csy on csy.code=spi.year left join ct_srm_dept fdept on fdept.id=spi.dept_id left join ct_srm_user fuser on fuser.id=spi.sub_user_id left join ct_srm_unit_order csuo on csuo.code=spi.our_unit_ranking left join ct_srm_patent_state sps on sps.code=spi.state left join ct_srm_patent_type spt on spt.code=spi.patent_type left join ct_srm_nationality csnl on csnl.code=spi.patent_country left join srm_patent_apply spapply on spapply.id=spi.apply_id where (spi.sub_user_id=#{patentInfoDto.userId} or spi.id in (SELECT patent_id FROM srm_patent_info_author WHERE author = #{patentInfoDto.userId}) )
and spi.name LIKE CONCAT('%', #{patentInfoDto.name}, '%')
and spi.patent_type =#{patentInfoDto.patentType}
and spi.patent_no =#{patentInfoDto.patentNo}
and spi.sub_date >= #{patentInfoDto.startDate}
and spi.sub_date <= #{patentInfoDto.endDate}
and spi.data_status = #{patentInfoDto.dataStatus}

select spi.id as rowId ,spi.data_status as dataStatus, spi.patent_no as patentNo ,spi.ann_no as annNo,spi.ann_date as annDate, spi.name as name ,spi.apply_date as applyDate,spi.apply_no as applyNo, spi.is_pct as isPct ,spi.cooperation_type as cooperationType, spi.pct_code as pctCode ,spi.pct_name as pctName, spi.pct_date as pctDate ,spi.pct_priority_date as pctPriorityDate, spi.certificate_no as certificateNo , csy.name as yearName, sps.name as stateName, fdept.name as deptName, fuser.name as subUserName, csuo.name as ourUnitRankingName, spt.name as patentTypeName from srm_patent_info spi left join ct_srm_year csy on csy.code=spi.year left join ct_srm_dept fdept on fdept.id=spi.dept_id left join ct_srm_user fuser on fuser.id=spi.sub_user_id left join ct_srm_unit_order csuo on csuo.code=spi.our_unit_ranking left join ct_srm_patent_state sps on sps.code=spi.state left join ct_srm_patent_type spt on spt.code=spi.patent_type left join srm_patent_apply spapply on spapply.id=spi.apply_id left join cf_srm_eaf_rec eafrec on eafrec.sys_no=spi.sys_no and eafrec.check_rec_id=spi.id where eafrec.step_no>1
and ((spi.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{patentInfoDto.userId}, '|%')) or (eafrec.step_no = (select max(step_no) from cf_srm_eaf_rec seafrec where spi.sys_no=seafrec.sys_no and seafrec.check_rec_id=spi.id) and eafrec.checker_string LIKE CONCAT('%|', #{patentInfoDto.userId}, '|%') and eafrec.check_datetime is not null) or (spi.data_status=0 and eafrec.is_current_step=1 and eafrec.check_result=3 and eafrec.checker_string LIKE CONCAT('%|', #{patentInfoDto.userId}, '|%')) )
and spi.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{patentInfoDto.userId}, '|%')
and spi.data_status=1 and eafrec.check_result="2" and eafrec.checker_string LIKE CONCAT('%|', #{patentInfoDto.userId}, '|%')
and spi.data_status=0 and eafrec.check_result="3" and eafrec.checker_string LIKE CONCAT('%|', #{patentInfoDto.userId}, '|%')
and spi.name LIKE CONCAT('%', #{patentInfoDto.name}, '%')
and spi.patent_type =#{patentInfoDto.patentType}
and spi.patent_no =#{patentInfoDto.patentNo}
and spi.sub_date >= #{patentInfoDto.startDate}
and spi.sub_date <= #{patentInfoDto.endDate}
order by eafrec.id desc
